                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                <div className="flex items-center gap-3 text-slate-300"><MapPin className="w-4 h-4 text-emerald-400" /><span>{selectedShift.location}</span></div>
